// ── Velocity Calculator ──────────────────────────────────────
const tickets = $node["📦 Fetch Sprint 1 Tickets"].json;
const empathyMaps = $node["🗺️ Fetch Empathy Map Progress"].json;

// Ticket metrics
const total       = tickets.length;
const done        = tickets.filter(t => t.status === 'Done').length;
const inProgress  = tickets.filter(t => t.status === 'In Progress').length;
const review      = tickets.filter(t => t.status === 'Review').length;
const backlog     = tickets.filter(t => t.status === 'Backlog' || t.status === 'To Do').length;
const velocityPct = total > 0 ? Math.round((done / total) * 100) : 0;

// By squad
const squads = ['UX Research', 'Core Dev', 'AI Integration', 'Growth/Marketing', 'Legal/Compliance'];
const squadMetrics = squads.map(squad => {
  const squadTickets = tickets.filter(t => t.squad === squad);
  const squadDone    = squadTickets.filter(t => t.status === 'Done').length;
  return { squad, total: squadTickets.length, done: squadDone };
});

// Empathy map progress
const mapsTotal    = empathyMaps.length;
const mapsComplete = empathyMaps.filter(m => m.is_complete).length;
const mapsPct      = mapsTotal > 0 ? Math.round((mapsComplete / mapsTotal) * 100) : 0;

// Stale tickets (updated > 2 days ago and not Done)
const twoDaysAgo = new Date(Date.now() - 2 * 24 * 60 * 60 * 1000);
const stale = tickets.filter(t => 
  t.status !== 'Done' && 
  new Date(t.updated_at) < twoDaysAgo
);

const today = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

// Build Slack message blocks
const slackMessage = {
  blocks: [
    {
      type: "header",
      text: { type: "plain_text", text: "📊 UniMart Sprint 1 — Daily Velocity Report", emoji: true }
    },
    {
      type: "context",
      elements: [{ type: "mrkdwn", text: `*${today}*  ·  Weeks 1–2  ·  EP-01` }]
    },
    { type: "divider" },
    {
      type: "section",
      fields: [
        { type: "mrkdwn", text: `*Total Tickets*\n${total}` },
        { type: "mrkdwn", text: `*✅ Done*\n${done} (${velocityPct}%)` },
        { type: "mrkdwn", text: `*🔄 In Progress*\n${inProgress}` },
        { type: "mrkdwn", text: `*👀 In Review*\n${review}` },
        { type: "mrkdwn", text: `*📋 Backlog/To Do*\n${backlog}` },
        { type: "mrkdwn", text: `*🗺️ Empathy Maps*\n${mapsComplete}/${mapsTotal} complete (${mapsPct}%)` }
      ]
    },
    { type: "divider" },
    {
      type: "section",
      text: { type: "mrkdwn", text: "*Squad Breakdown*" }
    },
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: squadMetrics.map(s => `• *${s.squad}*: ${s.done}/${s.total} done`).join('\n')
      }
    }
  ]
};

if (stale.length > 0) {
  slackMessage.blocks.push({ type: "divider" });
  slackMessage.blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*⚠️ Stale Tickets (${stale.length}) — not updated in 2+ days:*\n` +
            stale.slice(0, 5).map(t => `• [${t.squad}] ${t.title}`).join('\n') +
            (stale.length > 5 ? `\n_...and ${stale.length - 5} more_` : '')
    }
  });
}

return [{
  json: {
    slackMessage,
    metrics: { total, done, inProgress, review, backlog, velocityPct, mapsComplete, mapsTotal, staleCount: stale.length },
    squadMetrics,
    reportDate: today,
    sprint: 1
  }
}];
